    },
    {
      "source_requirement": "The ATM limits the number of failed PIN attempts before retaining the card for security reasons.",
      "rewritten_requirement": "The system shall limit the number of failed PIN attempts before retaining the card for security reasons."
    },
    {
      "source_requirement": "If the card is invalid (such as expired or reported stolen), the ATM retains the card for security reasons.",
